mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT TRIM(q.QUERY_ID) AS queryId, TRIM(q.QUERY_NAME) AS queryName, TRIM(q.SQL_GROUP_ID) AS sqlGroupId, TRIM(g.SQL_GROUP_NAME) AS sqlGroupName, TRIM(q.DB_ID) AS dbId, TRIM(c.DB_NAME) AS dbName, TRIM(q.SQL_TYPE) AS sqlType, TRIM(q.EXEC_TYPE) AS execType, q.CACHE_YN AS cacheYn, TRIM(q.TIME_OUT) AS timeOut, TRIM(q.RESULT_TYPE) AS resultType, q.USE_YN AS useYn, TRIM(q.QUERY_DESC) AS queryDesc, q.LAST_UPDATE_DTIME AS lastUpdateDtime, TRIM(q.LAST_UPDATE_USER_ID) AS lastUpdateUserId FROM FWK_SQL_QUERY q LEFT JOIN FWK_SQL_CONF c ON TRIM(q.DB_ID) = TRIM(c.DB_ID) LEFT JOIN FWK_SQL_GROUP g ON TRIM(q.SQL_GROUP_ID) = TRIM(g.SQL_GROUP_ID)
ORDER BY
TRIM(q.QUERY_NAME) TRIM(g.SQL_GROUP_NAME) q.USE_YN TRIM(q.QUERY_ID)
DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
